const NL = String.fromCharCode(10);
const items = $input.all();
const filtered = items.filter(function(item) {
  const url = item.json.screenshot_url;
  return url && typeof url === 'string' && url.indexOf('http') === 0;
});
const limited = filtered.slice(0, 10);
return limited.map(function(item) {
  return { json: item.json };
});

const NL = String.fromCharCode(10);
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const title = item.json.title || 'Unknown Script';
  const author = item.json.author || 'Unknown Author';
  const description = item.json.description || '';
  const script_url = item.json.script_url || '';
  const screenshot_url = item.json.screenshot_url || '';

  const systemLines = [
    'You are a senior quant trader with 15+ years experience. Be decisive and critical.',
    'Analyze this TradingView indicator screenshot and description.',
    'Describe the strategy logic in plain English (2-3 sentences).',
    'Estimate how it would perform on NVDA, SPY, TSLA over the last 6 months.',
    'Give an overall score from 1 to 10 (do not give 0/10 unless the script is completely broken or useless).',
    'Provide a short recommendation for the Quantum pipeline (e.g. High priority - strong volume profile, Medium - good for scalping, Low - too complex, Avoid - high risk of whipsaw).',
    'Be honest and critical. Always assign a real score.',
    '',
    'Respond in EXACTLY this JSON format (no markdown, no code blocks):',
    '{"strategy_logic":"2-3 sentences","performance_estimate":"NVDA/SPY/TSLA 6mo estimate","overall_score":1-10,"recommendation":"one line for Quantum"}',
    'Return ONLY valid JSON.'
  ];
  const systemContent = systemLines.join(NL);

  const userText = 'Script Title: ' + title + NL + 'Author: ' + author + NL + 'Description: ' + description;

  const body = {
    model: 'grok-4',
    messages: [
      {
        role: 'system',
        content: systemContent
      },
      {
        role: 'user',
        content: [
          {
            type: 'image_url',
            image_url: { url: screenshot_url }
          },
          {
            type: 'text',
            text: userText
          }
        ]
      }
    ],
    temperature: 0.2
  };

  results.push({
    json: {
      api_body: JSON.stringify(body),
      title: title,
      author: author,
      script_url: script_url,
      screenshot_url: screenshot_url,
      description: description
    }
  });
}

return results;

const NL = String.fromCharCode(10);
const grokResponses = $input.all();
const metadata = $('Build Vision Request').all();
const results = [];

for (let i = 0; i < grokResponses.length; i++) {
  const grok = grokResponses[i].json;
  const meta = metadata[i] ? metadata[i].json : {};

  let parsed = {};
  try {
    const content = grok.choices ? grok.choices[0].message.content : '';
    const clean = content.replace(/```json/g, '').replace(/```/g, '').trim();
    parsed = JSON.parse(clean);
  } catch (e) {
    parsed = { overall_score: 0, strategy_logic: 'Parse error', recommendation: 'Skip', performance_estimate: 'N/A' };
  }

  results.push({
    json: {
      title: meta.title || 'Unknown',
      author: meta.author || 'Unknown',
      script_url: meta.script_url || '',
      category: meta.category || '',
      screenshot_url: meta.screenshot_url || '',
      score: parsed.overall_score || 0,
      strategy_logic: parsed.strategy_logic || '',
      performance_estimate: parsed.performance_estimate || '',
      recommendation: parsed.recommendation || '',
      analyzed_at: new Date().toISOString()
    }
  });
}

results.sort((a, b) => (b.json.score || 0) - (a.json.score || 0));
results.forEach((r, i) => { r.json.rank = i + 1; });
return results;

const NL = String.fromCharCode(10);
const items = $input.all();
const top5 = items.slice(0, 5);
const count = top5.length;

const lines = [];
lines.push('<b>Vision Discovery \u2014 Top ' + count + ' new scripts analyzed</b>');
lines.push('');

for (let i = 0; i < top5.length; i++) {
  const item = top5[i];
  const rank = item.json.rank || (i + 1);
  const title = item.json.title || 'Untitled';
  const author = item.json.author || 'Unknown';
  const score = item.json.score || 0;
  const strategy = item.json.strategy_logic || '';
  const rec = item.json.recommendation || '';

  lines.push(rank + '. <b>' + title + '</b> - ' + author + ' \u2192 Score ' + score + '/10');
  lines.push('   Summary: ' + strategy);
  lines.push('   Rec: ' + rec);
  lines.push('');
}

const message = lines.join(NL);
return [{ json: { message: message } }];
